from pathlib import Path
text = Path('MainWindow.xaml').read_text(encoding='utf-8')
old = "                <!-- Left: scan status message + theme indicator -->\n                <StackPanel Grid.Column=\"0\" Orientation=\"Horizontal\" VerticalAlignment=\"Center\">\n                    <TextBlock x:Name=\"StatusText\"\n                               Text=\"Ready\" FontSize=\"11\"\n                               Foreground=\"{DynamicResource TextBrush}\"\n                               VerticalAlignment=\"Center\" />\n                    <TextBlock x:Name=\"ThemeIndicator\"\n                               Text=\"Theme: Light\" FontSize=\"10\"\n                               Margin=\"12,0,0,0\"\n                               Foreground=\"{DynamicResource HeaderTextBrush}\"\n                               VerticalAlignment=\"Center\" />\n                </StackPanel>\n"
new = "                <!-- Left: scan status message + theme toggle -->\n                <StackPanel Grid.Column=\"0\" Orientation=\"Horizontal\" VerticalAlignment=\"Center\" Spacing=\"12\">\n                    <TextBlock x:Name=\"StatusText\"\n                               Text=\"Ready\" FontSize=\"11\"\n                               Foreground=\"{DynamicResource TextBrush}\"\n                               VerticalAlignment=\"Center\" />\n                    <Button x:Name=\"ThemeToggleButton\"\n                            Content=\"Theme\"\n                            FontSize=\"10\"\n                            Padding=\"6,2\"\n                            Margin=\"12,0,0,0\"\n                            Click=\"ThemeToggleButton_Click\" />\n                </StackPanel>\n"
if old not in text:
    raise SystemExit('block not found')
Path('MainWindow.xaml').write_text(text.replace(old,new,1),encoding='utf-8')
